一、Composition API 中的生命周期钩子基础 1.1 从 Options API 到 Composition API 的过渡 在 Vue 2 的 Options API 中，我们通过选项对象的方式定义生命周期钩子，比如 mounted、updated 等。而在 Vue 3 的 Composition API 中，这些钩子被转换为了可导入的函数，需要我们显式调用并传入回调函数。
&lt;!-- Options API 写法 --&gt; &lt;script&gt; export default { mounted() { console.log(&#39;组件已挂载&#39;) } } &lt;/script&gt; &lt;!-- Composition API 写法 --&gt; &lt;script setup&gt; import {onMounted} from &#39;vue&#39; onMounted(() =&gt; { console.log(&#39;组件已挂载&#39;) }) &lt;/script&gt; 这种变化带来了更灵活的代码组织方式，我们可以将相关的逻辑集中在一起，而不是分散在不同的选项中。
1.2 生命周期钩子的对应关系 Vue 3 提供了与 Options API 相对应的 Composition API 生命周期钩子，以下是完整的对应表：
Options API Composition API 执行时机 beforeCreate 不需要（直接在 setup 中编写） 组件实例创建前 created 不需要（直接在 setup 中编写） 组件实例创建后 beforeMount onBeforeMount 组件挂载前 mounted onMounted 组件挂载后 beforeUpdate onBeforeUpdate 组件更新前 updated onUpdated 组件更新后 beforeUnmount onBeforeUnmount 组件卸载前 unmounted onUnmounted 组件卸载后 errorCaptured onErrorCaptured 捕获后代组件错误时 renderTracked onRenderTracked 响应式依赖被追踪时 renderTriggered onRenderTriggered 响应式依赖触发渲染时 1.3 生命周期钩子的执行顺序 为了更好地理解生命周期钩子的执行顺序，我们可以通过以下流程图来直观感受：
graph TD A[组件创建] --&gt; B[setup 执行] B --&gt; C[onBeforeMount] C --&gt; D[组件挂载到 DOM] D --&gt; E[onMounted] E --&gt; F[数据更新] F --&gt; G[onBeforeUpdate] G --&gt; H[DOM 更新] H --&gt; I[onUpdated] I --&gt; J[组件卸载] J --&gt; K[onBeforeUnmount] K --&gt; L[组件从 DOM 移除] L --&gt; M[onUnmounted] 二、生命周期钩子的组合技巧 2.1 逻辑分组与代码复用 在 Composition API 中，我们可以将相关的生命周期钩子和业务逻辑封装到同一个函数中，实现逻辑的分组和复用。
// useFetch.js import {ref, onMounted, onUnmounted} from &#39;vue&#39; export function useFetch(url) { const data = ref(null) const error = ref(null) const isLoading = ref(false) let controller = null const fetchData = async () =&gt; { isLoading.value = true try { controller = new AbortController() const response = await fetch(url, {signal: controller.signal}) data.value = await response.json() } catch (err) { if (err.name !== &#39;AbortError&#39;) { error.value = err } } finally { isLoading.value = false } } onMounted(() =&gt; { fetchData() }) onUnmounted(() =&gt; { if (controller) { controller.abort() } }) return {data, error, isLoading, fetchData} } 在组件中使用这个自定义 hook：
&lt;script setup&gt; import {useFetch} from &#39;./useFetch&#39; const {data, error, isLoading, fetchData} = useFetch(&#39;https://api.example.com/data&#39;) &lt;/script&gt; &lt;template&gt; &lt;div v-if=&#34;isLoading&#34;&gt;加载中...&lt;/div&gt; &lt;div v-else-if=&#34;error&#34;&gt;出错了: {{ error.message }}&lt;/div&gt; &lt;div v-else&gt;{{ JSON.stringify(data) }}&lt;/div&gt; &lt;button @click=&#34;fetchData&#34;&gt;重新加载&lt;/button&gt; &lt;/template&gt; 2.2 多个生命周期钩子的组合 我们可以在同一个自定义 hook 中组合多个生命周期钩子，实现更复杂的逻辑。
// useEventListener.js import {onMounted, onUnmounted} from &#39;vue&#39; export function useEventListener(target, event, callback) { onMounted(() =&gt; { target.addEventListener(event, callback) }) onUnmounted(() =&gt; { target.removeEventListener(event, callback) }) } 在组件中使用：
&lt;script setup&gt; import {ref} from &#39;vue&#39; import {useEventListener} from &#39;./useEventListener&#39; const windowWidth = ref(window.innerWidth) useEventListener(window, &#39;resize&#39;, () =&gt; { windowWidth.value = window.innerWidth }) &lt;/script&gt; &lt;template&gt; &lt;div&gt;窗口宽度: {{ windowWidth }}px&lt;/div&gt; &lt;/template&gt; 三、生命周期钩子的封装技巧 3.1 条件性生命周期钩子 我们可以根据条件来决定是否注册生命周期钩子，实现更灵活的逻辑控制。
// useIntersectionObserver.js import {ref, onMounted, onUnmounted} from &#39;vue&#39; export function useIntersectionObserver(target, options = {}) { const isIntersecting = ref(false) let observer = null onMounted(() =&gt; { if (typeof IntersectionObserver !== &#39;undefined&#39;) { observer = new IntersectionObserver(([entry]) =&gt; { isIntersecting.value = entry.isIntersecting }, options) observer.observe(target.value) } }) onUnmounted(() =&gt; { if (observer) { observer.disconnect() } }) return {isIntersecting} } 3.2 生命周期钩子的动态注册 在某些情况下，我们可能需要在组件运行时动态注册生命周期钩子。Vue 3 提供了 onScopeDispose 函数，可以在组件卸载时清理资源。
// useDynamicHook.js import {onScopeDispose} from &#39;vue&#39; export function useDynamicHook() { const addHook = (hook, callback) =&gt; { hook(callback) // 在组件卸载时清理 onScopeDispose(() =&gt; { // 这里可以添加清理逻辑 }) } return {addHook} } 四、课后 Quiz 问题 1：如何封装一个自定义 hook，实现监听窗口大小变化的功能？ 答案解析： 我们可以封装一个 useWindowSize 的自定义 hook，使用 useEventListener 来监听窗口的 resize 事件。
// useWindowSize.js import {ref} from &#39;vue&#39; import {useEventListener} from &#39;./useEventListener&#39; export function useWindowSize() { const width = ref(window.innerWidth) const height = ref(window.innerHeight) useEventListener(window, &#39;resize&#39;, () =&gt; { width.value = window.innerWidth height.value = window.innerHeight }) return {width, height} } 在组件中使用：
&lt;script setup&gt; import {useWindowSize} from &#39;./useWindowSize&#39; const {width, height} = useWindowSize() &lt;/script&gt; &lt;template&gt; &lt;div&gt;窗口大小: {{ width }}px × {{ height }}px&lt;/div&gt; &lt;/template&gt; 问题 2：在自定义 hook 中，如何处理组件卸载时的资源清理？ 答案解析： 在自定义 hook 中，我们可以使用 onUnmounted 或 onScopeDispose 来处理组件卸载时的资源清理。onUnmounted 专门用于组件卸载时的清理，而 onScopeDispose 则更通用，可以用于任何作用域的清理，比如在 setup 函数中创建的局部作用域。
// useTimer.js import {ref, onUnmounted} from &#39;vue&#39; export function useTimer(initialValue = 0) { const count = ref(initialValue) let timer = null const start = () =&gt; { timer = setInterval(() =&gt; { count.value&#43;&#43; }, 1000) } const stop = () =&gt; { if (timer) { clearInterval(timer) timer = null } } onUnmounted(() =&gt; { stop() }) return {count, start, stop} } 五、常见报错解决方案 错误 1：onMounted is not defined 产生原因：忘记导入 onMounted 函数。 解决办法：在使用 onMounted 之前，需要从 vue 中导入它。
import {onMounted} from &#39;vue&#39; 错误 2：生命周期钩子回调函数中的 this 指向错误 产生原因：在 Composition API 中，this 不再指向组件实例，所以不能像 Options API 那样使用 this。 解决办法：在 Composition API 中，我们应该直接使用定义的响应式变量和函数，而不是通过 this 访问。
// 错误写法 onMounted(() =&gt; { console.log(this.count) // this 指向 undefined }) // 正确写法 const count = ref(0) onMounted(() =&gt; { console.log(count.value) }) 错误 3：自定义 hook 中的响应式变量未正确更新 产生原因：在自定义 hook 中，可能没有正确使用响应式 API（如 ref、reactive）来定义变量。 解决办法：确保所有需要响应式的变量都使用 ref 或 reactive 来定义。
// 错误写法 export function useCounter() { let count = 0 // 不是响应式的 const increment = () =&gt; { count&#43;&#43; } return {count, increment} } // 正确写法 import {ref} from &#39;vue&#39; export function useCounter() { const count = ref(0) // 响应式变量 const increment = () =&gt; { count.value&#43;&#43; } return {count, increment} } 参考链接 Vue.js 官方文档 - Composition API 介绍 Vue.js 官方文档 - 生命周期钩子 余下文章内容请点击跳转至 个人博客页面 或者 扫描二维码 关注或者微信搜一搜：编程智域 前端至全栈交流与成长 ，阅读完整的文章：Vue 3 Composition API生命周期钩子：如何实现从基础理解到高阶复用？
